// =============================================================================
//  VMP MONITOR — Node "Code in JavaScript" cho n8n  (Mode: Run Once for All Items)
//  -----------------------------------------------------------------------------
//  ĐẶT NGAY SAU node Google Sheets → "Get row(s) in sheet".
//  Sau node này nối tới node "Respond to Webhook" (Respond With: First Incoming Item).
//
//  Ưu điểm:
//   • Khớp cột theo TÊN đã chuẩn hoá (bỏ dấu cách thừa, không phân biệt hoa/thường)
//     → vẫn đúng dù header có khoảng trắng thừa (vd "…hoàn thành đề cương ") hoặc lệch nhẹ.
//   • Tự đưa mọi kiểu ngày (số serial Google / Date / chuỗi ISO / dd-mm-yyyy) về dd/mm/yyyy.
//   • Bỏ qua dòng trống (không có Mã đối tượng).
//   • Trả về đúng định dạng web cần: { ok, count, rows: [...] }.
// =============================================================================

// ---- 1) Bản đồ: TÊN CỘT (đã chuẩn hoá) -> khoá ngắn dùng trong web ----
const COLS = {
  "stt":                                                      "stt",
  "phân loại đối tượng":                                      "phan_loai",
  "loại thẩm định":                                           "loai_td",
  "mã đối tượng":                                             "ma",
  "tên đối tượng":                                            "ten",
  "bộ phận quản lý":                                          "bo_phan",
  "mã khu vực":                                               "khu_vuc",
  "line":                                                     "line",
  "tình trạng":                                               "tinh_trang",
  "show":                                                     "show",
  "thẩm định":                                                "td",
  "tần suất thẩm định (tháng)":                               "tan_suat",
  "năm":                                                      "nam",
  "id thẩm định":                                             "id",
  "số ngày công thẩm định thực tế":                           "so_ngay_cong",
  "điểm trọng yếu":                                           "diem_trong_yeu",
  "phân loại báo cáo":                                        "phan_loai_bc",
  "qa phụ trách (qa nhập)":                                   "qa",
  "email (qa nhập)":                                          "email_qa",
  "nhân sự bộ phận khác (bộ phận khác nhập)":                 "ns_khac",
  "email (bộ phận khác nhập)":                                "email_khac",
  "deadline đề cương (t- 60 ngày)":                           "dl_de_cuong",
  "thời gian thực tế hoàn thành đề cương":                    "ngay_de_cuong",
  "trạng thái đề cương":                                      "tt_de_cuong",
  "deadline thẩm định thực tế (t-5-bc)":                      "dl_tham_dinh",
  "bộ phận quản lý xếp lịch thẩm định (dd/mm/yyyy hh:mm:ss)": "lich_td",
  "thời gian thực tế hoàn thành thẩm định thực tế":           "ngay_tham_dinh",
  "trạng thái thẩm định thực tế":                             "tt_tham_dinh",
  "deadline báo cáo (t-5 ngày)":                              "dl_bao_cao",
  "thời gian thực tế hoàn thành báo cáo":                     "ngay_bao_cao",
  "trạng thái báo cáo":                                       "tt_bao_cao",
  "deadline vmp (t)":                                         "dl_vmp",
  "thời gian thực tế deadline vmp":                           "ngay_vmp",
  "trạng thái vmp":                                           "tt_vmp",
};

// Chuẩn hoá: bỏ dấu cách thừa + về chữ thường + gộp nhiều dấu cách thành 1.
const norm = (s) => String(s == null ? "" : s).trim().toLowerCase().replace(/\s+/g, " ");
const pad  = (n) => String(n).padStart(2, "0");

// ---- 2) Đưa mọi kiểu ngày về "dd/mm/yyyy" ----
function toDMY(v) {
  if (v == null || v === "") return "";
  if (v instanceof Date && !isNaN(v)) return `${pad(v.getDate())}/${pad(v.getMonth() + 1)}/${v.getFullYear()}`;
  if (typeof v === "number" && isFinite(v)) {              // số serial của Google Sheets
    const d = new Date(Math.round((v - 25569) * 86400000)); // 25569 ngày: 1899-12-30 → 1970-01-01
    return `${pad(d.getUTCDate())}/${pad(d.getUTCMonth() + 1)}/${d.getUTCFullYear()}`;
  }
  const s = String(v).trim();
  const iso = s.match(/^(\d{4})-(\d{2})-(\d{2})/);          // yyyy-mm-dd...
  if (iso) return `${iso[3]}/${iso[2]}/${iso[1]}`;
  const dmy = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);    // dd/mm/yyyy...
  if (dmy) return `${pad(+dmy[1])}/${pad(+dmy[2])}/${dmy[3]}`;
  return s;
}

// Các cột là NGÀY (ép về dd/mm/yyyy). Cột "lich_td" giữ nguyên vì có cả giờ.
const DATE_KEYS = new Set([
  "dl_de_cuong", "ngay_de_cuong", "dl_tham_dinh", "ngay_tham_dinh",
  "dl_bao_cao", "ngay_bao_cao", "dl_vmp", "ngay_vmp",
]);

// ---- 3) Lặp qua từng dòng Sheet, dựng object theo khoá ngắn ----
const rows = [];
for (const item of $input.all()) {
  const src = item.json || {};

  // map: tên-cột-đã-chuẩn-hoá -> giá trị (để khớp dù header lệch dấu cách/hoa thường)
  const byNorm = {};
  for (const key of Object.keys(src)) byNorm[norm(key)] = src[key];

  const row = {};
  for (const headerNorm in COLS) {
    const shortKey = COLS[headerNorm];
    let val = byNorm[headerNorm];
    if (val == null) val = "";
    if (DATE_KEYS.has(shortKey)) val = toDMY(val);
    else if (typeof val === "string") val = val.trim();
    row[shortKey] = val;
  }

  // --- Fallback MỀM cho 2 cột SỐ quan trọng: nếu khớp chính xác không ra,
  //     dò theo từ khoá đặc trưng ("ngày công" / "trọng yếu") — an toàn vì
  //     không cột nào khác chứa các từ này. Giúp vẫn đọc đúng dù tiêu đề lệch chữ.
  if (String(row.so_ngay_cong).trim() === "") {
    const k = Object.keys(byNorm).find((h) => h.includes("ngày công") || h.includes("ngay cong"));
    if (k) { const v = byNorm[k]; row.so_ngay_cong = (typeof v === "string") ? v.trim() : v; }
  }
  if (String(row.diem_trong_yeu).trim() === "") {
    const k = Object.keys(byNorm).find((h) => h.includes("trọng yếu") || h.includes("trong yeu"));
    if (k) { const v = byNorm[k]; row.diem_trong_yeu = (typeof v === "string") ? v.trim() : v; }
  }

  // Bỏ dòng không có Mã đối tượng (dòng trống hoặc dòng chú thích).
  if (String(row.ma).trim() !== "") rows.push(row);
}

// ---- 4) Trả về cho web (ĐÚNG định dạng adapter cần) ----
return [{ json: { ok: true, count: rows.length, rows } }];

const raw = $json.body;
const p = typeof raw === 'string' ? JSON.parse(raw) : raw;

if (p.action === 'ping') return [{ json: { ok: true, pong: true, ts: Date.now() } }];
if (p.action !== 'updateRow' || !p.id) throw new Error('Thiếu action=updateRow hoặc id');

const pt = p.patch || {};
return [{ json: {
  id: p.id, user: p.user || '', ts: p.ts || '',
  ngay_de_cuong:  pt.ngay_de_cuong  ?? '',
  tt_de_cuong:    pt.tt_de_cuong    ?? '',
  lich_td:        pt.lich_td        ?? '',
  ngay_tham_dinh: pt.ngay_tham_dinh ?? '',
  tt_tham_dinh:   pt.tt_tham_dinh   ?? '',
  ngay_bao_cao:   pt.ngay_bao_cao   ?? '',
  tt_bao_cao:     pt.tt_bao_cao     ?? '',
  ngay_vmp:       pt.ngay_vmp       ?? '',
  tt_vmp:         pt.tt_vmp         ?? '',
} }];
